    # with optional spaces around the dash.
    tier_pattern = re.compile(r'\$?\s*51\s*[-\u2013\u2014]\s*\$?\s*500')

    best_found = []
    best_missing = ['original $5,000', 'recalculated $4,710', 'tier $51-$500']
