        is_payoff = bool(re.search(r'payoff|trade.{0,20}vari|gross', text))
        if not is_payoff:
            continue
        match_found = True

        has_original = bool(re.search(r'5[,.]?000', text))
        has_recalc = bool(re.search(r'4[,.]?710', text))
        has_tier = bool(tier_pattern.search(text))

        found = []
        missing = []
        if has_original: found.append('original $5,000')
        else: missing.append('original $5,000')
        if has_recalc: found.append('recalculated $4,710')
        else: missing.append('recalculated $4,710')
        if has_tier: found.append('tier $51-$500')
        else: missing.append('tier $51-$500')

        if not missing:
            return {'pass': True, 'score': 1.0, 'feedback': f'Trade payoff escalation includes all required figures and tier: {found}'}
