from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    actions_file = Path(workspace_path) / 'actions_summary.txt'
    if not actions_file.exists():
        return {'pass': False, 'score': 0.0,
                'feedback': 'actions_summary.txt not found in workspace.'}

    raw = actions_file.read_text(encoding='utf-8', errors='ignore')
    text = raw.lower()

    checks = {}

    # 1. Original total gross of $5,000 (allow $5,000 or $5000)
    checks['original_gross_5000'] = bool(
        re.search(r'\$\s*5[,\s]?000(?!\d)', text)
    )

    # 2. Recalculated total gross of $4,710 (allow $4,710 or $4710)
    checks['recalculated_gross_4710'] = bool(
        re.search(r'\$\s*4[,\s]?710(?!\d)', text)
    )

    # 3. $290 adjustment classified under the $51–$500 tier.
    #    Look for the tier string near a mention of $290 (within ~200 chars either side).
    tier_pattern = r'\$?\s*51\s*[-–—to]+\s*\$?\s*500'
    adj_290 = [m.start() for m in re.finditer(r'\$\s*290\b', text)]
    tier_hits = [m.start() for m in re.finditer(tier_pattern, text)]
    near = False
    for a in adj_290:
        for t in tier_hits:
            if abs(a - t) <= 200:
                near = True
                break
        if near:
            break
    checks['290_in_51_500_tier'] = near

    # 4. Escalation to Elena Brooks
    checks['escalated_to_elena_brooks'] = bool(
        re.search(r'elena\s+brooks', text)
    )

    # 5. No 1 business day / 1 BD delay before escalation.
    #    Fail if we see phrasing like "after 1 business day", "1 BD delay",
    #    "wait 1 business day", "following 1 business day", etc., in the
    #    vicinity of Elena Brooks / escalation language.
    delay_pattern = (
        r'(?:after|wait(?:ing)?|following|delay(?:ed)?\s+by|'
        r'within|once)\s+1\s*(?:bd\b|business\s+day)'
        r'|1\s*(?:bd\b|business\s+day)\s+(?:delay|wait|hold)'
    )
    has_bad_delay = bool(re.search(delay_pattern, text))
    checks['no_1bd_delay'] = not has_bad_delay

    passed = [k for k, v in checks.items() if v]
    missing = [k for k, v in checks.items() if not v]

    if not missing:
        return {'pass': True, 'score': 1.0,
                'feedback': f'All checks passed: {passed}'}
    return {'pass': False, 'score': len(passed) / len(checks),
            'feedback': f'Passed: {passed}; Failed: {missing}'}

